import { useEffect, useState } from 'react';

const useTimer = ({
  sec,
  setIsFirst,
  keepAfterRefresh,
}: {
  sec: number;
  setIsFirst: React.Dispatch<React.SetStateAction<boolean>>;
  keepAfterRefresh: boolean;
}) => {
  const [count, setCount] = useState<number>(0);
  const [intervalId, setIntervalId] = useState<NodeJS.Timeout>();

  const startTimer = () => {
    const endTime = new Date().getTime() + sec * 1000;
    if (keepAfterRefresh) document.cookie = `endTime=${endTime}; max-age=${sec}`;

    setCount(sec);

    const intervalId = setInterval(() => {
      setCount((prev) => prev - 1);
    }, 1000);

    setIntervalId(intervalId);
    setIsFirst(false);
  };

  const stopTimer = () => {
    document.cookie = 'endTime=; expires=Thu, 01 Jan 1970 00:00:01 GMT;';
    setCount(0);
  };

  useEffect(() => {
    const endTime = document.cookie.match('(^|;) ?' + 'endTime' + '=([^;]*)(;|$)');
    if (endTime) {
      const currentTime = new Date().getTime();
      const count = Math.floor((Number(endTime[2]) - currentTime) / 1000);

      setCount(count);

      const intervalId = setInterval(() => {
        setCount((prev) => prev - 1);
      }, 1000);

      setIntervalId(intervalId);
    }
  }, []);

  useEffect(() => {
    if (intervalId && count <= 0) {
      clearInterval(intervalId);
    }
  }, [intervalId, count]);

  return { count, startTimer, stopTimer };
};

export default useTimer;

 
'use client';

import { zodResolver } from '@hookform/resolvers/zod';
import Image from 'next/image';
import { useState } from 'react';
import { useForm } from 'react-hook-form';

import { usePostMockScore } from '@repo/api/hooks';
import { ARTS_PHYSICAL_SUBJECTS, GENERAL_SUBJECTS } from '@repo/constants';
import { useModalStore } from '@repo/store';
import {
  GEDAchievementType,
  GraduationTypeValueEnum,
  LiberalSystemValueEnum,
  MiddleSchoolAchievementType,
  Step4FormType,
  step4Schema,
  StepEnum,
} from '@repo/types';
import { ComputerRecommendedPage, Step4Register } from '@repo/ui/components';
import { Button } from '@repo/ui/shadcn';
import { cn } from '@repo/utils';

const graduationArray = [
  { text: '졸업 예정', value: GraduationTypeValueEnum.CANDIDATE, img: '/images/candidate.png' },
  { text: '졸업자', value: GraduationTypeValueEnum.GRADUATE, img: '/images/graduate.png' },
  { text: '검정고시', value: GraduationTypeValueEnum.GED, img: '/images/ged.png' },
];

const CalculatePage = () => {
  const { setScoreCalculationCompleteModal } = useModalStore();

  const step4UseForm = useForm<Step4FormType>({
    resolver: zodResolver(step4Schema),
    defaultValues: {
      liberalSystem: LiberalSystemValueEnum.FREE_SEMESTER,
      freeSemester: null,
      gedAvgScore: null,
    },
  });

  const [graduationType, setGraduationType] = useState<GraduationTypeValueEnum | null>(null);
  const [errorStep, setErrorStep] = useState<StepEnum | null>(null);
  const isCandidate = graduationType === GraduationTypeValueEnum.CANDIDATE;
  const isGED = graduationType === GraduationTypeValueEnum.GED;
  const isGraduate = graduationType === GraduationTypeValueEnum.GRADUATE;
  const isStep4Success = step4Schema.safeParse(step4UseForm.watch()).success;

  const { mutate: postMockScore } = usePostMockScore(graduationType!, {
    onSuccess: (data) => {
      setScoreCalculationCompleteModal(true, data, 'mock');
    },
  });

  const handleCalculateButtonClick = () => {
    const {
      liberalSystem,
      achievement1_1,
      achievement1_2,
      achievement2_1,
      achievement2_2,
      achievement3_1,
      achievement3_2,
      newSubjects,
      artsPhysicalAchievement,
      absentDays,
      attendanceDays,
      volunteerTime,
      freeSemester,
      gedAvgScore,
    } = step4UseForm.watch();

    const body: MiddleSchoolAchievementType | GEDAchievementType = isGED
      ? {
          gedAvgScore: gedAvgScore!,
        }
      : {
          liberalSystem: liberalSystem,
          achievement1_1: achievement1_1!,
          achievement1_2: achievement1_2!,
          achievement2_1: achievement2_1!,
          achievement2_2: achievement2_2!,
          achievement3_1: achievement3_1!,
          achievement3_2: achievement3_2!,
          newSubjects: newSubjects,
          artsPhysicalAchievement: artsPhysicalAchievement!,
          absentDays: absentDays!,
          attendanceDays: attendanceDays!,
          volunteerTime: volunteerTime!,
          freeSemester: freeSemester || '',
          generalSubjects: [...GENERAL_SUBJECTS],
          artsPhysicalSubjects: [...ARTS_PHYSICAL_SUBJECTS],
        };

    postMockScore(body);
  };

  const handleCalculateStepError = () => {
    setErrorStep(StepEnum.FOUR);
  };

  const clearStepError = () => {
    setErrorStep(null);
  };

  const handleCalculateClick = () => {
    if (isStep4Success) {
      handleCalculateButtonClick();
    } else {
      handleCalculateStepError();
    }
  };

  const handleBackClick = () => {
    step4UseForm.reset({
      liberalSystem: LiberalSystemValueEnum.FREE_SEMESTER,
      freeSemester: null,
      gedAvgScore: null,
    });
    setErrorStep(null);
    setGraduationType(null);
  };

  return (
    <>
      <ComputerRecommendedPage type="calculate" />
      {graduationType ? (
        <div className={cn('mdx:flex', 'justify-center', 'rounded-[1.25rem]', 'hidden')}>
          <div className={cn('mb-[3.56rem]', 'bg-white', 'mt-[3.56rem]', 'rounded-[1.25rem]')}>
            <header
              className={cn(
                'w-266',
                'flex',
                'justify-end',
                'px-7',
                'h-[4.25rem]',
                'items-center',
                'rounded-t-[1.25rem]',
                'gap-2',
                'border-b-[0.0625rem]',
                'border-gray-100',
              )}
            >
              <Button onClick={handleBackClick} variant="ghost">
                이전
              </Button>
              <Button
                form="scoreForm"
                type="submit"
                variant={isStep4Success ? 'next' : 'submit'}
                onClick={handleCalculateClick}
              >
                내 성적 계산하기
              </Button>
            </header>
            <div className={cn('p-8', 'pt-6', 'pb-10')}>
              <Step4Register
                graduationType={graduationType}
                isCandidate={isCandidate}
                isGED={isGED}
                isGraduate={isGraduate}
                type="calculate"
                {...step4UseForm}
                showError={errorStep === StepEnum.FOUR}
                clearStepError={clearStepError}
              />
            </div>
          </div>
        </div>
      ) : (
        <div className={cn('mdx:flex', 'w-full', 'justify-center', 'mt-48', 'hidden')}>
          <div className={cn('flex', 'flex-col', 'items-center', 'gap-10')}>
            <h1 className={cn('text-[1.5rem]/[2rem]', 'text-gray-900', 'font-semibold')}>
              모의 성적 계산을 위한 지원자 유형을 선택해 주세요.
            </h1>
            <div className={cn('flex', 'gap-5', 'w-[39.4375rem]')}>
              {graduationArray.map(({ text, value, img }) => (
                <button
                  key={value}
                  className={cn(
                    'h-28',
                    'pt-5',
                    'pl-5',
                    'w-[12.3125rem]',
                    'bg-white',
                    'rounded-xl',
                    'flex',
                    'flex-col',
                    'justify-between',
                  )}
                  onClick={() => setGraduationType(value)}
                >
                  <h1
                    className={cn(
                      'text-[1rem]/[1.5rem]',
                      'text-gray-800',
                      'font-semibold',
                      'text-start',
                    )}
                  >
                    {text}
                  </h1>
                  <Image
                    src={img}
                    width={56}
                    height={56}
                    alt={text}
                    className={cn('ml-[5.81rem]')}
                  />
                </button>
              ))}
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default CalculatePage;

'use client';

import { useQueryClient } from '@tanstack/react-query';
import type { AxiosError } from 'axios';
import { useRouter } from 'next/navigation';
import { useEffect, useRef } from 'react';
import { toast } from 'react-toastify';

import { useOAuthLogin } from '@repo/api/hooks';
import { memberQueryKeys } from '@repo/api/lib';
import { cn } from '@repo/utils';

interface ErrorResponse {
  message?: string;
}

const CallbackPage = ({ code, provider }: { code: string; provider: string }) => {
  const router = useRouter();
  const queryClient = useQueryClient();
  const isCalled = useRef(false);

  const handleLoginSuccess = async () => {
    await queryClient.invalidateQueries({ queryKey: memberQueryKeys.getMyMemberInfo() });

    const nextUrl =
      provider === 'admin' ? `${window.location.origin}/?isAdmin=true` : window.location.origin;
    router.replace(nextUrl);
  };

  const handleLoginError = (error: AxiosError) => {
    router.replace('/');
    const errorMessage = (error.response?.data as ErrorResponse)?.message;
    if (errorMessage === '학교 이메일로 가입해주세요.') {
      toast.error('테스트 기간에는 로그인할 수 없습니다.');
    } else {
      toast.error('로그인에 실패했습니다.');
    }
  };

  const { mutate: googleLogin } = useOAuthLogin('google', {
    onSuccess: handleLoginSuccess,
    onError: handleLoginError,
  });

  const { mutate: kakaoLogin } = useOAuthLogin('kakao', {
    onSuccess: handleLoginSuccess,
    onError: handleLoginError,
  });

  useEffect(() => {
    if (isCalled.current) return;
    isCalled.current = true;

    if (!code || !provider) {
      router.replace('/');
      toast.error('로그인에 실패했습니다.');
      return;
    }

    const redirectUri = `${window.location.origin}/callback`;

    if (provider === 'google' || provider === 'admin') {
      googleLogin({ code, redirectUri });
    } else if (provider === 'kakao') {
      kakaoLogin({ code, redirectUri });
    } else {
      router.replace('/');
      toast.error('로그인에 실패했습니다.');
    }
  }, [code, provider]);

  return (
    <div className={cn('flex', 'h-[calc(100vh-4.625rem)]', 'items-center', 'justify-center')}>
      <div className={cn('text-lg', 'font-medium')}>로그인 처리 중...</div>
    </div>
  );
};

export default CallbackPage;

'use client';

import { useState } from 'react';

import { useModalStore } from '@repo/store';
import { MyMemberInfoType, MyTotalTestResultType } from '@repo/types';
import { cn } from '@repo/utils';

import { PassResultDialog } from '@/components';

const divStyle = [
  'text-gray-900',
  'text-[1rem]/[1.5rem]',
  'font-semibold',
  'w-[12.3125rem]',
  'h-[6.5rem]',
  'bg-white',
  'rounded-xl',
  'p-5',
  'flex',
  'relative',
  'shadow-md',
  'cursor-pointer',
] as const;

const imgStyle = ['absolute', 'top-[2.75rem]', 'right-[1.12rem]'] as const;

const containerStyle = ['flex', 'flex-col', 'gap-10', 'items-center'] as const;

const h1Style = ['text-gray-900', 'text-[1.5rem]/[2rem]', 'font-semibold'] as const;

interface CheckResultPageProps {
  memberInfo: MyMemberInfoType | undefined;
  resultInfo: MyTotalTestResultType | undefined;
  isCheckFirstResult: boolean;
  isCheckFinalResult: boolean;
  isOneseoWrite: boolean;
}

const CheckResultPage = ({
  memberInfo,
  resultInfo,
  isCheckFirstResult,
  isCheckFinalResult,
  isOneseoWrite,
}: CheckResultPageProps) => {
  const {
    setResultAnnouncementPeriodModal,
    setOneseoNotSubmittedModal,
    setResultNotAnnouncedModal,
  } = useModalStore();
  const [isFirstTest, setIsFirstTest] = useState<boolean>(true);
  const [isDialog, setIsDialog] = useState(false);

  const handleDialog = (resultStatus: boolean) => {
    // 원서를 작성하지 않았을 경우
    if (isOneseoWrite) return setOneseoNotSubmittedModal(true);

    // 원서를 작성했지만 결과가 null로 오는 경우
    if (
      (resultInfo && resultInfo.firstTestPassYn === null && isCheckFirstResult && resultStatus) ||
      (resultInfo && resultInfo.secondTestPassYn === null && isCheckFinalResult && !resultStatus)
    ) {
      return setResultNotAnnouncedModal(true);
    }

    const isChecked = resultStatus ? isCheckFirstResult : isCheckFinalResult;
    if (isChecked) {
      // 합격여부모달
      return setIsDialog(true);
    } else if (!isChecked) {
      // 조회 기간이 아닐경우
      return setResultAnnouncementPeriodModal(true, resultStatus);
    }
  };

  const handleCheckTest = (resultStatus: boolean) => {
    setIsFirstTest(resultStatus);
    handleDialog(resultStatus);
  };

  const handleDialogClick = () => {
    setIsDialog(false);
  };

  return (
    <>
      <div className={cn([containerStyle, 'mt-48'])}>
        <h1 className={cn([h1Style])}>합격 유형을 선택해주세요.</h1>
        <div className={cn('flex', 'gap-5', 'xs:flex-row', 'flex-col')}>
          <div onClick={() => handleCheckTest(true)} className={cn([divStyle])}>
            1차 합격 조회
            <img src="/images/🍀.png" className={cn([imgStyle, 'w-[3.75rem]', 'h-[3.75rem]'])} />
          </div>
          <div onClick={() => handleCheckTest(false)} className={cn([divStyle])}>
            최종 합격 조회
            <img src="/images/🏆.png" className={cn([imgStyle, 'w-[3.75rem]', 'h-[3.125rem]'])} />
          </div>
        </div>
      </div>

      <PassResultDialog
        isPassOpen={isDialog}
        setIsPassOpen={setIsDialog}
        isFinishFirstTest={isFirstTest}
        resultInfo={
          isFirstTest
            ? ({
                firstTestPassYn: resultInfo?.firstTestPassYn,
              } as MyTotalTestResultType)
            : resultInfo
        }
        memberInfo={{ name: memberInfo?.name } as MyMemberInfoType}
        onClick={handleDialogClick}
      />
    </>
  );
};

export default CheckResultPage;

